import numpy as np

def mirror_latitude(pitch_deg):
    sin2a = np.sin(np.radians(pitch_deg))**2
    for lam in np.linspace(0, np.pi/2, 10000):
        lhs = np.cos(lam)**6 / np.sqrt(1 + 3*np.sin(lam)**2)
        if lhs <= sin2a:
            return np.degrees(lam)
    return 90.0

print(f'{"Pitch angle":>12} {"Mirror lat":>12} {"Mirror alt (L=2)":>18}')
print('-' * 45)
for pa in [10, 15, 20, 30, 45, 60, 75, 85]:
    ml = mirror_latitude(pa)
    # Mirror altitude: r_mirror = L * cos^2(lambda_m) * R_earth
    r_mirror = 2.0 * np.cos(np.radians(ml))**2 * 6371  # km
    alt = r_mirror - 6371  # km above surface
    print(f'{pa:>10}° {ml:>10.1f}° {alt:>14.0f} km')
    if alt < 100:
        print(f'  *** IN LOSS CONE (mirror below atmosphere) ***')
